class ReportFormatterFactory {
    static ReportFormatter createForOutputFormat(OutputFormat format) {
        switch (format) {
            case PDF:  return new PdfReportFormatter();
            case CSV:  return new CsvReportFormatter();
            case HTML: return new HtmlReportFormatter();
            case JSON: return new JsonReportFormatter();
        }
        throw new IllegalArgumentException("Unsupported output format: " + format);
    }
}
